// src/Posts/PostDetailPage.js

import { useContext, useEffect, useState } from "react";
import { AuthContext } from "../AuthContext";
import PostCard from "../components/PostCard";
import CommentSection from "../CommentSection";

export default function PostDetailPage() {
    const { user } = useContext(AuthContext);

    const [post, setPost] = useState(null);
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState("");
    const [loading, setLoading] = useState(true);

    /* Extract postId from hash: #/post/123 */
    const postId = (() => {
        const m = (window.location.hash || "").match(/^#\/post\/(\d+)/i);
        return m ? Number(m[1]) : null;
    })();

    /* ===================== FETCH POST ===================== */

    const fetchPost = async () => {
        const usernameParam = user?.username
            ? `?username=${encodeURIComponent(user.username)}`
            : "";

        const res = await fetch(`/api/posts${usernameParam}`);
        const data = await res.json();

        const found = Array.isArray(data)
            ? data.find(p => p.id === postId)
            : null;

        setPost(found || null);
    };

    /* ===================== FETCH COMMENTS ===================== */

    const fetchComments = async () => {
        const usernameParam = user?.username
            ? `?username=${encodeURIComponent(user.username)}`
            : "";

        const res = await fetch(
            `/api/posts/${postId}/comments${usernameParam}`
        );

        const data = await res.json();
        setComments(Array.isArray(data) ? data : []);
    };

    /* ===================== INITIAL LOAD ===================== */

    useEffect(() => {
        if (!postId) return;

        (async () => {
            try {
                setLoading(true);
                await fetchPost();
                await fetchComments();
            } catch (e) {
                console.error("Failed to load post detail", e);
            } finally {
                setLoading(false);
            }
        })();
    }, [postId, user]);

    /* ===================== OPTIMISTIC REPLY ===================== */

    const makeTempComment = (text, parentId = null) => ({
        id: `temp-${Date.now()}`,
        username: user.username,
        comment: text,
        createdAt: new Date().toISOString(),
        reactions: { counts: {}, myReaction: null },
        parentId,
        optimistic: true
    });

    const postReply = async (text, parentId = null) => {
        if (!user || !text.trim()) return;

        const temp = makeTempComment(text, parentId);
        setComments(prev => [...prev, temp]);
        setNewComment("");

        try {
            const res = await fetch(`/api/posts/${postId}/comments`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    username: user.username,
                    comment: text,
                    parentId
                })
            });

            if (!res.ok) throw new Error();

            const saved = await res.json();

            setComments(prev =>
                prev.map(c => (c.id === temp.id ? saved : c))
            );
        } catch (e) {
            setComments(prev => prev.filter(c => c.id !== temp.id));
            alert("Failed to post reply");
        }
    };

    /* ===================== LIKE HANDLER ===================== */

    const toggleLike = async () => {
        if (!user || !post) return;

        const url = `/api/posts/${post.id}/like?username=${encodeURIComponent(
            user.username
        )}`;

        try {
            await fetch(url, {
                method: post.myLike ? "DELETE" : "POST"
            });

            fetchPost();
        } catch (e) {
            console.error("Like failed", e);
        }
    };

    /* ===================== GUARDS ===================== */

    if (!postId) {
        return <p>Invalid post link.</p>;
    }

    if (loading) {
        return <p>Loading…</p>;
    }

    if (!post) {
        return <p>Post not found.</p>;
    }

    /* ===================== RENDER ===================== */

    return (
        <div className="post-detail">
            <PostCard
                post={post}
                user={user}
                onLike={toggleLike}
            />

            <CommentSection
                comments={comments}
                user={user}
                newComment={newComment}
                setNewComment={setNewComment}
                onSubmit={(e) => {
                    postReply(newComment);
                }}
                onReply={postReply}
                enableReplies
            />
        </div>
    );
}
